DROP TABLE IF EXISTS `tbl_transaksi_header`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_transaksi_header` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `peopleId` bigint(20) DEFAULT NULL,
  `paramId` int(11) DEFAULT NULL,
  `title` varchar(128) NOT NULL,
  `isCash` tinyint(4) DEFAULT NULL,
  `satuan` varchar(30) DEFAULT NULL,
  `tanggal_transaksi` date DEFAULT NULL,
  `dokumen` varchar(100) DEFAULT NULL,
  `keterangan` varchar(200) DEFAULT NULL,
  `amount` bigint(20) DEFAULT NULL,
  `inOut` varchar(10) DEFAULT NULL COMMENT 'I = Masuk, O = Keluar',
  `isDeleted` tinyint(4) NOT NULL DEFAULT '0',
  `createdBy` int(11) NOT NULL,
  `createdDtm` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedBy` int(11) DEFAULT NULL,
  `updatedDtm` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=323 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

