/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER before_insert_transaksi_header
BEFORE INSERT ON tbl_transaksi_header
FOR EACH ROW
BEGIN
    DECLARE existing_id INT;

    -- Check if record exists in tbl_saldo_kas
    SELECT id INTO existing_id FROM tbl_saldo_kas WHERE paramId = NEW.paramId;

    IF existing_id IS NULL THEN
        -- If not exists, insert a new record
        INSERT INTO tbl_saldo_kas (paramId, total_masuk, total_keluar, createdBy, createdDtm)
        VALUES (NEW.paramId, 0, 0, NEW.createdBy, NEW.createdDtm);
    END IF;

    -- Update the totals based on the inOut value
    IF NEW.inOut = 'I' THEN
        UPDATE tbl_saldo_kas 
        SET total_masuk = total_masuk + NEW.amount, updatedBy = NEW.createdBy, updatedDtm = NEW.createdDtm 
        WHERE paramId = NEW.paramId;
    ELSE
        UPDATE tbl_saldo_kas 
        SET total_keluar = total_keluar + NEW.amount, updatedBy = NEW.createdBy, updatedDtm = NEW.createdDtm 
        WHERE paramId = NEW.paramId;
    END IF;
END */;;
DELIMITER ;
