/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER after_update_transaksi_header
AFTER UPDATE ON tbl_transaksi_header
FOR EACH ROW
BEGIN
    DECLARE existing_id INT;

    -- Check if record exists in tbl_saldo_kas
    SELECT id INTO existing_id FROM tbl_saldo_kas WHERE paramId = NEW.paramId;

    IF existing_id IS NULL THEN
        -- If not exists, insert a new record
        INSERT INTO tbl_saldo_kas (paramId, total_masuk, total_keluar, createdBy, createdDtm)
        VALUES (NEW.paramId, 0, 0, NEW.updatedBy, NEW.updatedDtm);
    END IF;

    -- Reverse the previous amount adjustment
    IF OLD.inOut = 'I' THEN
        UPDATE tbl_saldo_kas 
        SET total_masuk = total_masuk - OLD.amount 
        WHERE paramId = OLD.paramId;
    ELSE
        UPDATE tbl_saldo_kas 
        SET total_keluar = total_keluar - OLD.amount 
        WHERE paramId = OLD.paramId;
    END IF;

    -- Apply the new amount adjustment
    IF NEW.inOut = 'I' THEN
        UPDATE tbl_saldo_kas 
        SET total_masuk = total_masuk + NEW.amount, updatedBy = NEW.updatedBy, updatedDtm = NEW.updatedDtm 
        WHERE paramId = NEW.paramId;
    ELSE
        UPDATE tbl_saldo_kas 
        SET total_keluar = total_keluar + NEW.amount, updatedBy = NEW.updatedBy, updatedDtm = NEW.updatedDtm 
        WHERE paramId = NEW.paramId;
    END IF;
END */;;
DELIMITER ;
