/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER after_delete_transaksi_header
AFTER DELETE ON tbl_transaksi_header
FOR EACH ROW
BEGIN
    DECLARE existing_id INT;

    -- Check if record exists in tbl_saldo_kas
    SELECT id INTO existing_id FROM tbl_saldo_kas WHERE paramId = OLD.paramId;

    -- Adjust totals
    IF OLD.inOut = 'I' THEN
        UPDATE tbl_saldo_kas 
        SET total_masuk = total_masuk - OLD.amount, updatedBy = OLD.updatedBy, updatedDtm = OLD.updatedDtm 
        WHERE paramId = OLD.paramId;
    ELSE
        UPDATE tbl_saldo_kas 
        SET total_keluar = total_keluar - OLD.amount, updatedBy = OLD.updatedBy, updatedDtm = OLD.updatedDtm 
        WHERE paramId = OLD.paramId;
    END IF;

    -- Optionally delete the record from tbl_saldo_kas if no transactions left
    IF (SELECT COUNT(*) FROM tbl_transaksi_header WHERE paramId = OLD.paramId) = 0 THEN
        DELETE FROM tbl_saldo_kas WHERE paramId = OLD.paramId;
    END IF;
END */;;
DELIMITER ;
